import json
from pathlib import Path
from anthropic import Anthropic

client = Anthropic()

EVAL_DATASET = Path("evals/customer_support.jsonl")
PASS_RATE_MINIMUM = 0.85

def load_eval_cases(path: Path) -> list[dict]:
    with open(path) as f:
        return [json.loads(line) for line in f if line.strip()]

def run_offline_eval(model: str) -> dict:
    cases = load_eval_cases(EVAL_DATASET)
    passed = 0

    for case in cases:
        response = client.messages.create(
            model=model,
            max_tokens=1024,
            system=case["system"],
            messages=[{"role": "user", "content": case["input"]}],
        )
        output = response.content[0].text
        score = judge_output(case, output)
        if score >= case.get("threshold", 0.7):
            passed += 1

    pass_rate = passed / len(cases)
    return {
        "pass_rate": pass_rate,
        "passed": passed,
        "total": len(cases),
        "gate": pass_rate >= PASS_RATE_MINIMUM,
    }

def judge_output(case: dict, output: str) -> float:
    """Score output 0.0–1.0 using a model judge."""
    prompt = f"""Rate this response on the rubric below. Return only a float 0.0-1.0.

Rubric: {case['rubric']}
User input: {case['input']}
Agent response: {output}

Score:"""
    result = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=8,
        messages=[{"role": "user", "content": prompt}],
    )
    try:
        return float(result.content[0].text.strip())
    except ValueError:
        return 0.0

if __name__ == "__main__":
    result = run_offline_eval("claude-opus-4-8")
    status = "PASS" if result["gate"] else "FAIL"
    print(f"[{status}] {result['pass_rate']:.1%} ({result['passed']}/{result['total']})")

from statistics import mean

DEGRADATION_THRESHOLD = 0.05   # alert if score drops more than 5 pp

def rolling_score(conn: sqlite3.Connection, window_hours: int = 24) -> float | None:
    rows = conn.execute(
        """SELECT score FROM live_samples
           WHERE score IS NOT NULL
             AND sampled_at >= datetime('now', ?)
        """,
        (f"-{window_hours} hours",),
    ).fetchall()
    if not rows:
        return None
    return mean(r[0] for r in rows)

def check_degradation(conn: sqlite3.Connection, baseline: float) -> dict:
    current = rolling_score(conn, window_hours=24)
    if current is None:
        return {"status": "insufficient_data"}
    delta = current - baseline
    return {
        "current": current,
        "baseline": baseline,
        "delta": delta,
        "alert": delta < -DEGRADATION_THRESHOLD,
    }

# ci_gate.py — run in CI before every deployment

def run_ci_gate(model: str) -> None:
    result = run_offline_eval(model)

    print(f"Pass rate:  {result['pass_rate']:.1%}")
    print(f"Cases:      {result['passed']}/{result['total']}")
    print(f"Threshold:  {PASS_RATE_MINIMUM:.0%}")

    if not result["gate"]:
        raise SystemExit(
            f"[BLOCK] Pass rate {result['pass_rate']:.1%} below {PASS_RATE_MINIMUM:.0%}"
        )
    print("[PASS] Deployment approved.")

if __name__ == "__main__":
    run_ci_gate("claude-opus-4-8")

from dataclasses import dataclass

@dataclass
class OnlineMetrics:
    mean_score: float
    variance: float
    refusal_rate: float
    tool_failure_rate: float

ALERT_RULES = {
    "score_drop": lambda m, b: m.mean_score < b.mean_score - 0.05,
    "variance_spike": lambda m, b: m.variance > b.variance * 2.5,
    "refusal_surge": lambda m, b: m.refusal_rate > b.refusal_rate + 0.10,
    "tool_failures": lambda m, _: m.tool_failure_rate > 0.15,
}

def evaluate_alerts(current: OnlineMetrics, baseline: OnlineMetrics) -> list[str]:
    return [name for name, rule in ALERT_RULES.items() if rule(current, baseline)]
